            aOrbiterJ = ((aOrbiterJ + aOrbiterK) + 0x529C30994F25C948ULL) + aPhaseAOrbiterUpdateSaltB[((aIndex + 23U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0x4FA8106C3719E7B9ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x09CBCEAAEDCCC727ULL), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterA) + 0x1D6B9DEED0DA686FULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0xA555E23B6892C045ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x244ECF46284B80A1ULL), 3U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterG) + 0xDA9CC13B8E59D2E7ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0xED1AF0751D6E66DCULL;
            aOrbiterC = RotL64((aOrbiterC * 0x1FC6A15721D9CC45ULL), 41U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 0x3BDB3842C5DF9046ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterI) ^ 0x8C74FB6AA6409B3CULL) ^ aPhaseAOrbiterUpdateSaltE[((aIndex + 10U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0x1B52C569C3856449ULL), 23U);
            //
            aIngress = aOrbiterE ^ RotL64(aOrbiterJ, 35U);
            aIngress = aIngress + (RotL64(aOrbiterB, 3U) ^ aOrbiterA);
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterK, 18U));
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterD, 13U));
            aIngress = aIngress + RotL64(aOrbiterG, 57U);
