        // Ingress:
        //      aExpandLaneA (-->), aExpandLaneB (-->), aWindLaneD (-->), aInvestLaneC (<-?->)
        //
        // Cross:
        //      aExpandLaneC (<--), aExpandLaneD (<--), aWindLaneB (<-?->)
        //
