            aOrbiterD = (aWandererD + RotL64(aScatter, 13U)) + 0xC90E724E8B2A0C73ULL;
            aOrbiterH = ((aWandererF + RotL64(aIngress, 43U)) + RotL64(aCarry, 5U)) + 0x61B4D3EA24E9CA0BULL;
            aOrbiterC = ((aWandererA + RotL64(aCross, 5U)) + RotL64(aCarry, 29U)) + 0x250B0D87531A5148ULL;
            aOrbiterG = (((aWandererG + RotL64(aPrevious, 57U)) + RotL64(aCarry, 37U)) + 0x20F112A12B220C9BULL) + aPhaseHOrbiterAssignSaltD[(((31U - aIndex) + 24U)) & S_SALT1];
            aOrbiterF = (aWandererI + RotL64(aIngress, 24U)) + 0x9DA3E0CBC3E5EA05ULL;
