            //
            aOrbiterA = (aOrbiterA + aOrbiterE) + 0x8E2AEBF59F859F04ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterA) ^ 0x317B7E0E64083E35ULL) ^ aPhaseHOrbiterUpdateSaltF[((aIndex + 5U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x8215AA79B260BFA3ULL), 47U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterD) + 0x5F788D76E2B9105AULL) + aPhaseHOrbiterUpdateSaltB[((aIndex + 19U)) & S_SALT1];
            aOrbiterC = ((aOrbiterC ^ aOrbiterH) ^ 0x47D7BA37A92516CBULL) ^ aPhaseHOrbiterUpdateSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xF97384DF33E127A9ULL), 39U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 0x462B5449DD5192B7ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 0x69D1A5196719EE73ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x6D96D04AF3F71513ULL), 13U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterI) + 0x2EF83A14635124AAULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterD) ^ 0x6282DF21E3277533ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x84AD994107608AF9ULL), 53U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 0x0FD226728B6BBCF1ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterE) ^ 0xFC4C1F782BB8C181ULL) ^ aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0xBCE6272E276CA7B3ULL), 21U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0x531F641BA9362D55ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterJ) ^ 0x7F30C99F1FD7AAA8ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xDEDAA3B527C09625ULL), 57U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x375BA596DE2560BAULL;
