            //
            aOrbiterI = (aOrbiterI + aOrbiterH) + 0x6B98DFC26D7E5F52ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 0x5BBEBEE94D38459EULL;
            aOrbiterF = RotL64((aOrbiterF * 0x5032D7C92BE781F9ULL), 43U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 0x130EA899E6249CF1ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 0x9DB1FA46901A4D4AULL;
