            //
            aWandererF = aWandererF + (((RotL64(aScatter, 51U) + RotL64(aOrbiterG, 30U)) + aOrbiterI) + aPhaseHWandererUpdateSaltB[(((31U - aIndex) + 22U)) & S_SALT1]);
            aWandererK = aWandererK ^ ((RotL64(aPrevious, 23U) + RotL64(aOrbiterJ, 47U)) + aOrbiterD);
